import { getAuthenticationCookie } from '../lib';
import dotenv from 'dotenv';

async function script() {
  return getAuthenticationCookie({
    username: process.env.OKTA_AUTH_COOKIE_IPN as string,
    password: process.env.OKTA_AUTH_COOKIE_PASSWORD as string,
    appUrl: process.env.OKTA_AUTH_COOKIE_URL as string,
  });
}

dotenv.config();

script()
  .then((cookie: any) => {
    console.log(cookie);
  })
  .catch((error: Error) => {
    console.log(error);
    process.exit(1);
  });
